#include <iostream>
#include <string>

class Solution {
public:
    bool backspaceCompare(std::string s, std::string t) {
        int count_s = count_backspaces(s);
        int count_t = count_backspaces(t);
        return count_s == count_t;
    }

    int count_backspaces(std::string str) {
        int count = 0;
        for (char c : str) {
            if (c == '#') {
                count++;
            }
        }
        return count;
    }
};
```

